+    await adapter.executeTool("type", { text: "4*5" }, logger);
+    await adapter.executeTool("press", { key: "Enter" }, logger);
+    await new Promise((r) => setTimeout(r, 300));
+
+    const result = await adapter.executeTool("read_screen", {}, logger);
